###############################################################################
# benchmark/compare_author_vs_edid.R
#
# Validates R edid() against the author's reference implementation
# (efficient_did_unc_stagg from Chen, Sant'Anna & Xie 2025, shared code).
#
# Dataset: diffdiff benchmark panel (n=300, T=10, ATT=2, cohorts 0/3/5/7)
#          generated by: python3 benchmark/generate_diffdiff_benchmark.py
#
# Usage (from project root):
#   Rscript benchmark/compare_author_vs_edid.R
#   or in RStudio: source("benchmark/compare_author_vs_edid.R")
###############################################################################

rm(list = ls())

suppressPackageStartupMessages({
  devtools::load_all(quiet = TRUE)
  library(dplyr)
  library(BMisc)   # required by es_efficient() for TorF() / getListElement()
})

source("benchmark/edid_sim_original.R")   # loads efficient_did_unc_stagg()

panel_path <- file.path("benchmark", "data", "diffdiff_panel.csv")
if (!file.exists(panel_path)) {
  stop("Benchmark panel not found.\n",
       "Run: python3 benchmark/generate_diffdiff_benchmark.py")
}
panel <- read.csv(panel_path)

cat("═══════════════════════════════════════════════════════════════════════\n")
cat(" Author (CSX reference code) vs R edid() — staggered, no covariates   \n")
cat("═══════════════════════════════════════════════════════════════════════\n\n")
cat("Data: n =", length(unique(panel$unit)),
    " | T =", length(unique(panel$period)),
    " | periods:", paste(sort(unique(panel$period)), collapse = " "),
    " | cohorts:", paste(sort(unique(panel$first_treat)), collapse = " "),
    "(0 = never-treated)\n")
cat("True ATT = 2.0\n\n")


# ── A.  Author's efficient_did_unc_stagg ──────────────────────────────────────
#
# Key design choices in the author's code:
#   1. Comparison cohorts (g') iterate over TREATED cohorts only [3, 5, 7].
#      Never-treated (G=0) is NOT used as a comparison cohort (gp).
#   2. The never-treated (G=0) appears ONLY as the direct control:
#         E[Y_inf(t) - Y_inf(t')]
#   3. Valid (g', t') pairs:
#         g'==g   -> t_min  <= t' < g'  (includes period_1 = t_min)
#         g'!=g   -> t_min  <  t' < g'  (excludes period_1)
#   4. Omega is estimated as sample cov of the per-pair influence functions.

cat("─── A. Author's efficient_did_unc_stagg ────────────────────────────────\n")

res_author <- efficient_did_unc_stagg(
  data         = panel,
  yname        = "outcome",
  tname        = "period",
  gname        = "first_treat",
  idname       = "unit",
  return_weights = TRUE
)

wt_author <- as.data.frame(res_author$weights)
# Count valid pairs per (g,t) cell
n_pairs_author <- wt_author |>
  group_by(group, time) |>
  summarise(n_pairs_author = n(), .groups = "drop") |>
  filter(time >= group)   # post-treatment only

post_mask_auth <- res_author$time >= res_author$group
auth_gt <- data.frame(
  group  = res_author$group[post_mask_auth],
  time   = res_author$time[post_mask_auth],
  att_a  = round(res_author$estimate[post_mask_auth], 4),
  se_a   = round(res_author$std.error[post_mask_auth], 4)
)

cat("\nPost-treatment ATT(g,t) -- author:\n")
print(auth_gt, row.names = FALSE)


# ── B.  R edid() (PT-All, nevertreated) ───────────────────────────────────────
#
# Key design choices in our R edid():
#   1. Comparison cohorts (gp) include BOTH treated cohorts [3,5,7] AND
#      the never-treated cohort (gp=Inf).
#   2. Valid (gp, tpre) pairs (for finite gp):
#         tpre < eff_start(gp)  AND  tpre != period_1   (period_1 = 0 here)
#      For gp=Inf:
#         tpre can be any period except period_1
#   3. Omega is computed analytically from closed-form within-group covariances.
#   4. The EIF is computed per unit and uses (after yesterday's fix) the full
#      baseline-shift term when gp=Inf.

cat("\n─── B. R edid() PT-All nevertreated ────────────────────────────────────\n")

# first_treat=0 -> edid() auto-converts to Inf (never-treated)
res_r <- edid(
  data          = panel,
  yname         = "outcome",
  idname        = "unit",
  tname         = "period",
  gname         = "first_treat",
  pt_assumption = "all",
  control_group = "nevertreated",
  alp           = 0.05
)

r_gt_all <- res_r$att_gt[!is.na(res_r$att_gt$att), ]
r_gt <- r_gt_all[!r_gt_all$is_pre, c("group", "time", "att", "se")]
names(r_gt)[3:4] <- c("att_r", "se_r")
r_gt$att_r <- round(r_gt$att_r, 4)
r_gt$se_r  <- round(r_gt$se_r,  4)

# n_pairs per cell from the cell objects
n_pairs_r <- vapply(res_r$cells, function(x) x$n_pairs %||% 0L, integer(1L))
cell_idx <- data.frame(
  group   = vapply(res_r$cells, `[[`, numeric(1), "group"),
  time    = vapply(res_r$cells, `[[`, numeric(1), "time"),
  is_pre  = vapply(res_r$cells, `[[`, logical(1), "is_pre"),
  n_pairs = n_pairs_r
)
n_pairs_r_post <- cell_idx[!cell_idx$is_pre, c("group", "time", "n_pairs")]
names(n_pairs_r_post)[3] <- "n_pairs_r"

cat("\nPost-treatment ATT(g,t) -- R edid():\n")
print(r_gt, row.names = FALSE)


# ── C.  Side-by-side comparison ───────────────────────────────────────────────
cat("\n─── C. Side-by-side: author vs R edid() ────────────────────────────────\n")

cmp <- merge(auth_gt, r_gt, by = c("group", "time"))
cmp <- merge(cmp, n_pairs_author,  by = c("group", "time"), all.x = TRUE)
cmp <- merge(cmp, n_pairs_r_post,  by = c("group", "time"), all.x = TRUE)
cmp <- cmp[order(cmp$group, cmp$time), ]

cmp$diff_att <- round(cmp$att_r  - cmp$att_a, 4)
cmp$diff_se  <- round(cmp$se_r   - cmp$se_a,  4)

print(cmp[, c("group", "time",
              "n_pairs_author", "n_pairs_r",
              "att_a", "att_r", "diff_att",
              "se_a",  "se_r",  "diff_se")],
      row.names = FALSE)

cat(sprintf("\nMax |diff| ATT : %.5f\n", max(abs(cmp$diff_att), na.rm = TRUE)))
cat(sprintf("Max |diff| SE  : %.5f\n", max(abs(cmp$diff_se),  na.rm = TRUE)))
cat(sprintf("Median SE ratio (author/edid): %.3f  (>1 => edid is more efficient)\n",
            median(cmp$se_a / cmp$se_r, na.rm = TRUE)))


# ── D.  Structural differences summary ───────────────────────────────────────
cat("\n─── D. Structural differences (moments / valid pairs) ──────────────────\n")

# Enumerate author's pairs and our pairs for one representative cell: (g=3, t=3)
g_ex <- 3; t_ex <- 3
auth_pairs_ex <- wt_author[wt_author$group == g_ex & wt_author$time == t_ex,
                            c("g_prime", "t_prime")]
names(auth_pairs_ex) <- c("gp", "tpre")
auth_pairs_ex <- auth_pairs_ex[order(auth_pairs_ex$gp, auth_pairs_ex$tpre), ]

# Our pairs: from the panel object
# re-derive manually for transparency
periods  <- sort(unique(panel$period))
period_1 <- min(periods)
cohorts  <- sort(unique(panel$first_treat[panel$first_treat > 0]))
r_pairs_ex <- do.call(rbind, lapply(c(cohorts, Inf), function(gp) {
  if (is.finite(gp)) {
    valid_tpre <- periods[periods < gp & periods != period_1]
  } else {
    valid_tpre <- periods[periods != period_1]
  }
  if (length(valid_tpre) == 0) return(NULL)
  data.frame(gp = gp, tpre = valid_tpre)
}))
r_pairs_ex <- r_pairs_ex[order(r_pairs_ex$gp, r_pairs_ex$tpre), ]

cat(sprintf("\nFor cell (g=%d, t=%d):\n", g_ex, t_ex))
cat(sprintf("  Author: %d pairs  [g' ∈ {3,5,7} only, never-treated NOT a comparison cohort]\n",
            nrow(auth_pairs_ex)))
cat(sprintf("  edid(): %d pairs  [gp ∈ {3,5,7,Inf}, period_1=%d excluded]\n",
            nrow(r_pairs_ex), period_1))

cat("\n  Author's pairs (g_prime, t_prime):\n")
print(auth_pairs_ex, row.names = FALSE)

cat("\n  edid() pairs (gp, tpre)  [Inf = never-treated]:\n")
r_pairs_print <- r_pairs_ex
r_pairs_print$gp <- ifelse(is.infinite(r_pairs_print$gp), "Inf", as.character(r_pairs_print$gp))
print(r_pairs_print, row.names = FALSE)

cat("\n  Pairs in author but NOT in edid():  (g'=g, t'=period_1) pairs\n")
in_auth_not_r <- author_only <- auth_pairs_ex[
  auth_pairs_ex$tpre == period_1 & auth_pairs_ex$gp == g_ex, ]
if (nrow(in_auth_not_r) == 0) {
  cat("    none\n")
} else {
  print(in_auth_not_r, row.names = FALSE)
  cat("    Note: when g'=g and t'=period_1, IF_g_prime = 0, so this pair\n")
  cat("    contributes zero new information (reduces to standard CS DiD).\n")
}

cat("\n  Pairs in edid() but NOT in author:  gp=Inf pairs\n")
inf_only <- r_pairs_ex[is.infinite(r_pairs_ex$gp), ]
inf_only$gp <- "Inf"
print(inf_only, row.names = FALSE)
cat("    Note: gp=Inf pairs exploit the never-treated cohort as\n")
cat("    comparison cohort, providing additional identifying moments.\n")


# ── E.  Overall ATT comparison ────────────────────────────────────────────────
cat("\n─── E. Overall ATT ─────────────────────────────────────────────────────\n")

# Author: compute aggregated overall = cohort-share weighted average of post cells
glist_auth  <- sort(unique(panel$first_treat[panel$first_treat > 0]))
n_auth <- length(unique(panel$unit))
pi_g   <- sapply(glist_auth, function(g) mean(panel$first_treat == g))
names(pi_g) <- as.character(glist_auth)

auth_att_overall <- sum(vapply(glist_auth, function(g) {
  idx <- which(auth_gt$group == g)
  if (length(idx) == 0) return(0)
  pi_g[as.character(g)] * mean(auth_gt$att_a[idx])
}, numeric(1))) / sum(pi_g)

cat(sprintf("  Author overall ATT (manual avg): %.4f\n", auth_att_overall))
cat(sprintf("  R edid() overall ATT           : %.4f   SE = %.4f   CI = [%.4f, %.4f]\n",
            res_r$overall$att, res_r$overall$se,
            res_r$overall$ci_lower, res_r$overall$ci_upper))
cat("  True ATT = 2.0\n")


# ── F.  Omega: sample-cov (author) vs analytical (edid) ─────────────────────
cat("\n─── F. Omega* comparison: sample cov (author) vs analytical (edid) ──────\n")
cat("Check whether the two Omega matrices agree for cell (g=3, t=3).\n\n")

# Author's Omega for (g=3, t=3)
auth_if <- as.matrix(res_author$eff_inf_function)   # n x n_gt
# find column index for (g=3, t=3)
g3t3_col_auth <- which(
  res_author$group == g_ex & res_author$time == t_ex
)
# Get the raw (pre-combination) IFs: stored in att_gt_results which we don't
# have directly. Re-run with lower-level access.
# Recompute inside the function scope by running directly:
cat("(Re-running IF computation for (g=3,t=3) to extract raw Omega...)\n")

df_tmp <- as.data.frame(panel)
Y_tmp   <- df_tmp$outcome
Time_tmp <- df_tmp$period
G_tmp   <- df_tmp$first_treat
sample_size_tmp <- length(unique(df_tmp$unit))
G_cs_tmp <- G_tmp[Time_tmp == min(Time_tmp)]
tlist_tmp <- sort(unique(df_tmp$period))
glist_tmp <- sort(unique(df_tmp$first_treat))
g_treated_tmp <- glist_tmp[glist_tmp > 0]
pi2_tmp <- sapply(glist_tmp, function(gv) mean(G_tmp == gv))

# The pairs for (g=3, tt=3) as in author's code
pairs_3_3 <- auth_pairs_ex   # already extracted above

# Compute per-pair IFs
IF_mat_auth <- matrix(0, nrow = sample_size_tmp, ncol = nrow(pairs_3_3))
for (kk in seq_len(nrow(pairs_3_3))) {
  gp_v  <- pairs_3_3$gp[kk]
  tp_v  <- pairs_3_3$tpre[kk]
  mean_g_t      <- mean(Y_tmp[G_tmp==g_ex & Time_tmp==t_ex]) -
                   mean(Y_tmp[G_tmp==g_ex & Time_tmp==min(Time_tmp)])
  mean_inf_tpre <- mean(Y_tmp[G_tmp==0 & Time_tmp==t_ex]) -
                   mean(Y_tmp[G_tmp==0 & Time_tmp==tp_v])
  mean_gp_tpre  <- mean(Y_tmp[G_tmp==gp_v & Time_tmp==tp_v]) -
                   mean(Y_tmp[G_tmp==gp_v & Time_tmp==min(Time_tmp)])
  IF_g    <- (G_cs_tmp==g_ex)/pi2_tmp[which(glist_tmp==g_ex)] *
             (Y_tmp[Time_tmp==t_ex] - Y_tmp[Time_tmp==min(Time_tmp)] - mean_g_t)
  IF_inf  <- (G_cs_tmp==0)/pi2_tmp[which(glist_tmp==0)] *
             (Y_tmp[Time_tmp==t_ex] - Y_tmp[Time_tmp==tp_v] - mean_inf_tpre)
  IF_gp   <- (G_cs_tmp==gp_v)/pi2_tmp[which(glist_tmp==gp_v)] *
             (Y_tmp[Time_tmp==tp_v] - Y_tmp[Time_tmp==min(Time_tmp)] - mean_gp_tpre)
  IF_mat_auth[, kk] <- IF_g - (IF_inf + IF_gp)
}

Omega_auth_sample <- cov(IF_mat_auth)   # 13 x 13

# Our edid() Omega for (g=3, t=3): re-derive from panel_obj
panel_obj_r <- did:::prepare_edid_panel(
  data = panel,
  yname = "outcome", idname = "unit", tname = "period", gname = "first_treat",
  control_group = "nevertreated"
)
# Convert G=0 -> Inf first (as edid() does)
panel2 <- panel
panel2$first_treat[panel2$first_treat == 0] <- Inf
panel_obj_r2 <- did:::prepare_edid_panel(
  data = panel2,
  yname = "outcome", idname = "unit", tname = "period", gname = "first_treat",
  control_group = "nevertreated"
)
pairs_r_3_3 <- did:::enumerate_valid_pairs_edid(
  target_g = g_ex,
  treatment_groups = panel_obj_r2$treatment_groups,
  time_periods     = panel_obj_r2$time_periods,
  period_1         = panel_obj_r2$period_1,
  pt_assumption    = "all"
)
Omega_r_analytical <- did:::compute_omega_star_nocov_edid(
  target_g      = g_ex,
  target_t      = t_ex,
  pairs         = pairs_r_3_3,
  panel_obj     = panel_obj_r2,
  pt_assumption = "all"
)

cat(sprintf("  Author Omega (sample cov):     %d x %d matrix\n",
            nrow(Omega_auth_sample), ncol(Omega_auth_sample)))
cat(sprintf("  edid() Omega (analytical):     %d x %d matrix\n",
            nrow(Omega_r_analytical), ncol(Omega_r_analytical)))

# Compare condition numbers
kappa_auth <- max(svd(Omega_auth_sample, nu=0, nv=0)$d) /
              min(svd(Omega_auth_sample, nu=0, nv=0)$d[
                svd(Omega_auth_sample, nu=0, nv=0)$d > 0])
kappa_r    <- max(svd(Omega_r_analytical, nu=0, nv=0)$d) /
              min(svd(Omega_r_analytical, nu=0, nv=0)$d[
                svd(Omega_r_analytical, nu=0, nv=0)$d > 0])
cat(sprintf("\n  Condition number (author Omega): %.2e\n", kappa_auth))
cat(sprintf("  Condition number (edid Omega) : %.2e\n", kappa_r))


cat("─── Done ────────────────────────────────────────────────────────────────\n")
